      // ----- trailing‑edge (default) mode -----
      // Remember the latest context / arguments.
      lastArgs = args;
      lastThis = this;

      // Reset the wait timer.
      if (timer) clearTimeout(timer);
      timer = setTimeout(() => {
        timer = null;
        // Invoke with the most recent arguments if we have any.
        if (lastArgs) {
          fn.apply(lastThis, lastArgs);
          lastArgs = null;
          lastThis = null;
        }
      }, ms);
    }
  } as T & { cancel(): void };

  // Attach the `cancel` method.
  debounced.cancel = () => {
    if (timer) {
      clearTimeout(timer);
      timer = null;
