    }

    if (!leading || pending) {
      // Trailing edge: remember the latest `this` and args while the window is open.
      lastArgs = args;
      lastThis = this;
    }

    timer = setTimeout(() => {
      timer = undefined;
      if (lastArgs !== undefined) {
        fn.apply(lastThis, lastArgs);
        lastArgs = undefined;
        lastThis = undefined;
      }
    }, ms);
  } as T & { cancel(): void };

  debounced.cancel = () => {
    if (timer !== undefined) {
      clearTimeout(timer);
      timer = undefined;
    }
    lastArgs = undefined;
    lastThis = undefined;
  };

  return debounced;
}
```

### Behavior

- **Trailing by default** (`leading: false`): calls within `ms` reset the timer; `fn` runs once after the window expires with the most recent `this` and arguments.
- **Leading mode** (`leading: true`): the first call in a quiet window executes immediately. Further calls within `ms` are suppressed for immediate execution but update the captured `this`/args, so a trailing call fires with the latest values once the window closes. If there are no follow-up calls, no trailing call occurs.
- **`.cancel()`** clears any pending timer and discards captured `this`/arguments.
- **`this` and argument types** are preserved via `ThisParameterType<T>` and `Parameters<T>`.
- No external dependencies.
